<template>
  <div>
    <div
        class="mb-1 skill" @mouseenter="handleEffect"
        v-for="(skill, skillName) in skills">
      <p>
        {{skillName}}
        <span v-if="skill.skill_level" class="ml-2 score-dots">
          <span v-for="i in score_base"  class="mx-0.5">
            <font-awesome-icon
                class="mb-0.5"
                :data-count="i"
                :class="{'filled-dot':i <= skill.skill_level}"
                :style="{color: i <= skill.skill_level ? 'rgb(134 232 134)' : '#CCC', fontSize:'10px', animationDelay:(.5) + (i*0.1) + 's'}"
                icon="circle"/>
          </span>
        </span>
      </p>
      <p class="text-xs italic ml-3">[ {{ skill.frameworks.join(', ') }} ]</p>
    </div>
  </div>
</template>

<script>
export default {
  name: "ProfessionalSkills",
  props:{
    skills:{
      required:true,
      type:Object
    },
    score_base:{
      type:Number,
      default: 5
    }
  },
  methods:{
    handleEffect(e){
      e.target.querySelectorAll('.filled-dot').forEach(x => {
        if (!x.classList.contains('filled-dot-animated')){
          setTimeout( () => x.classList.remove('filled-dot-animated'), 1500)
          x.classList.add('filled-dot-animated')
        }
      })
    }
  }
}
</script>

<style scoped lang="less">
 *{
   text-align: left;
 }

 .skill:hover{
   /*.filled-dot{
     animation-name: dot-boop;
     animation-fill-mode: forwards;
     animation-duration: .3s;
     animation-timing-function: linear;
   }*/
 }

 .filled-dot-animated{
   animation-name: dot-boop;
   animation-fill-mode: forwards;
   animation-duration: .3s;
   animation-timing-function: linear;
 }

 @keyframes dot-boop {
   50% { transform: scale(1.4); }
   100% { transform: scale(1); }
 }

</style>
